#include<stdio.h>

int main()
{
	int n, k, x;

	scanf("%d %d", &n, &k);

	if((n-k)>=(k-1))
	{
		x=k-1;
	}
	else
	{
		x=n-k;
	}
	printf("%d", (n*3)+x);

	return 0;
}

